#!/bin/bash
# install-pre-commit.sh — drops a .git/hooks/pre-commit wrapper that runs
# the three doc-integrity linters. Idempotent: re-running overwrites the
# installed wrapper.
#
# This is the ONLY place that ties the three helpers into git; individual
# helpers are runnable standalone for ad-hoc validation.

set -eu
REPO_ROOT="$(git rev-parse --show-toplevel)"
HOOK="$REPO_ROOT/.git/hooks/pre-commit"

cat > "$HOOK" <<'WRAPPER'
#!/bin/bash
# Auto-generated by helpers/install-pre-commit.sh. Do not edit directly;
# regenerate via: bash helpers/install-pre-commit.sh
set -u
REPO_ROOT="$(git rev-parse --show-toplevel)"
FAIL=0

run_hook() {
  local name="$1"
  local script="$REPO_ROOT/helpers/$name"
  [ -x "$script" ] || { echo "[pre-commit] missing or non-exec: $script"; return 0; }
  if ! bash "$script"; then
    echo "[pre-commit] FAIL: $name"
    FAIL=1
  fi
}

run_hook doc-reality-check.sh
run_hook lessons-lint.sh
run_hook skills-shape-lint.sh

exit $FAIL
WRAPPER
chmod +x "$HOOK"
echo "[install-pre-commit] wrote $HOOK"
